/bin/zsh -lc "python -c \"import pandas as pd, statsmodels.formula.api as smf; df=pd.read_csv('dataset.csv');
for c in ['ad_budget_usd','time_of_day_hour','channel_score','page_load_time_sec','previous_visits']: df[c+'_z']=(df[c]-df[c].mean())/df[c].std();
m_base=smf.logit('converted ~ ad_budget_usd_z + time_of_day_hour_z + channel_score_z + page_load_time_sec_z + previous_visits_z + C(device)', data=df).fit(disp=False);
m_inter=smf.logit('converted ~ ad_budget_usd_z + time_of_day_hour_z * channel_score_z + page_load_time_sec_z + previous_visits_z + C(device)', data=df).fit(disp=False);
m_timequad=smf.logit('converted ~ ad_budget_usd_z + time_of_day_hour_z + I(time_of_day_hour_z**2) + channel_score_z + page_load_time_sec_z + previous_visits_z + C(device)', data=df).fit(disp=False);
m_scorequad=smf.logit('converted ~ ad_budget_usd_z + time_of_day_hour_z + channel_score_z + I(channel_score_z**2) + page_load_time_sec_z + previous_visits_z + C(device)', data=df).fit(disp=False);
print('AIC base', round(m_base.aic,3)); print('AIC interaction', round(m_inter.aic,3)); print('AIC time quad', round(m_timequad.aic,3)); print('AIC score quad', round(m_scorequad.aic,3)); print('interaction coef', m_inter.params['time_of_day_hour_z:channel_score_z']); print('interaction p', m_inter.pvalues['time_of_day_hour_z:channel_score_z']); print('time quad p', m_timequad.pvalues['I(time_of_day_hour_z ** 2)']); print('score quad p', m_scorequad.pvalues['I(channel_score_z ** 2)'])\""

