/bin/zsh -lc "python -c \"import pandas as pd, statsmodels.formula.api as smf, numpy as np; df=pd.read_csv('dataset.csv');
for c in ['ad_budget_usd','time_of_day_hour','channel_score','page_load_time_sec','previous_visits']: df[c+'_z']=(df[c]-df[c].mean())/df[c].std();
m=smf.logit('converted ~ ad_budget_usd_z + time_of_day_hour_z * channel_score_z + page_load_time_sec_z + previous_visits_z + C(device)', data=df).fit(disp=False);
p=m.predict(df); y=df['converted'];
pearson=((y-p)/np.sqrt(p*(1-p))); print('pearson residual mean', pearson.mean()); print('pearson residual std', pearson.std());
# calibration by deciles
q=pd.qcut(p, 10, duplicates='drop'); cal=df.assign(pred=p, bin=q).groupby('bin', observed=False).agg(pred_mean=('pred','mean'), obs_rate=('converted','mean'), n=('converted','size')); print(cal.to_string())\""

